// This file is generated by tools/gen only if it does not already exist.
// Once present, tools/gen never overwrites it - edit freely to add real
// assertions (this scaffold only proves create+read-back with placeholder
// values).
func TestAccVariableCustomjsfunction_createAndReadBack(t *testing.T) {
	testAccPreCheck(t)
	resourceName := "matomo_tagmanager_variable_customjsfunction.test"

	resource.Test(t, resource.TestCase{
		ProtoV6ProviderFactories: testAccProtoV6ProviderFactories,
		Steps: []resource.TestStep{
			{
				Config: testAccVariableCustomjsfunctionConfig(),
				Check: resource.ComposeAggregateTestCheckFunc(
					resource.TestCheckResourceAttrSet(resourceName, "id"),
				),
			},
			{
				ResourceName:      resourceName,
				ImportState:       true,
				ImportStateVerify: true,
			},
		},
	})
}

func testAccVariableCustomjsfunctionConfig() string {
	return `
provider "matomo" {}

resource "matomo_site" "test" {
  name = "Generated CustomJsFunction Acceptance Site"
  urls = ["https://acc-generated-customjsfunction.example.com"]
}

resource "matomo_tagmanager_container" "test" {
  site_id = matomo_site.test.id
  context = "web"
  name    = "Generated CustomJsFunction Acceptance Container"
}

resource "matomo_tagmanager_variable_customjsfunction" "test" {
  container_id = matomo_tagmanager_container.test.id
  name         = "generated-test-customjsfunction"
  // CustomJsFunctionVariable.php requires the value to start with the
  // literal word "function" (confirmed live and by reading the source).
  js_function = "function() { return 'test-value'; }"
}
`
}
